const { SUPABASE_URL, SUPABASE_ANON_KEY } = window.APP_CONFIG || {};
const sb = SUPABASE_URL && SUPABASE_ANON_KEY ? window.supabase.createClient(SUPABASE_URL, SUPABASE_ANON_KEY) : null;
const currency = new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',maximumFractionDigits:0});
const fmt = n => currency.format(Number(n||0));
function getTodayLocal(){
  const d=new Date();
  const y=d.getFullYear();
  const m=String(d.getMonth()+1).padStart(2,'0');
  const day=String(d.getDate()).padStart(2,'0');
  return `${y}-${m}-${day}`;
}
const today = getTodayLocal();
let selectedDate = today;
let pageState = {};
const PAGE_SIZE = 10;
let db = emptyDb();
let currentUser = null;
let currentProfile = null;
let supplierReportState = { supplierId: null, from: null, to: null };
let dailyCashFlowDate = today;
const isOwner = () => currentProfile?.role === 'owner';

function emptyDb(){return {ownerCash:[],dailyExpenses:[],dailyClosings:[],suppliers:[],purchases:[],weeklyExpenses:[],payments:[],supplierDownPayments:[]};}
function parseDate(s){const [y,m,d]=s.split('-').map(Number);return new Date(y,m-1,d)}
function iso(d){return new Date(d.getTime()-d.getTimezoneOffset()*60000).toISOString().slice(0,10)}
function getCycle(dateStr){const d=parseDate(dateStr);const day=d.getDay();const offset=day===0?-6:1-day;const start=new Date(d);start.setDate(d.getDate()+offset);const end=new Date(start);end.setDate(start.getDate()+5);return {start:iso(start),end:iso(end)}}
function inCycle(date,cycle){return date>=cycle.start&&date<=cycle.end}
function cycleData(){const c=getCycle(selectedDate);return {c,ownerCash:db.ownerCash.filter(x=>inCycle(x.date,c)),dailyExpenses:db.dailyExpenses.filter(x=>inCycle(x.date,c)),dailyClosings:db.dailyClosings.filter(x=>inCycle(x.date,c)),purchases:db.purchases.filter(x=>inCycle(x.date,c)),weeklyExpenses:db.weeklyExpenses.filter(x=>inCycle(x.date,c)),supplierDownPayments:db.supplierDownPayments.filter(x=>inCycle(x.date,c))}}
function sum(arr,key='amount'){return arr.reduce((a,b)=>a+Number(b[key]||0),0)}
function supplierName(id){return db.suppliers.find(s=>s.id===id)?.name||'Supplier tidak ditemukan'}
function dpAppliedForPurchase(purchaseId){return sum(db.supplierDownPayments.filter(d=>d.appliedPurchaseId===purchaseId),'appliedAmount')}
function openDownPaymentsForSupplier(supplierId){return latestSort(db.supplierDownPayments.filter(d=>d.supplierId===supplierId&&!d.appliedPurchaseId&&Number(d.amount)>0))}
function purchasePaidFor(purchaseId){return paidFor('purchase',purchaseId)+dpAppliedForPurchase(purchaseId)}
function downPaymentOutOnDate(date){return sum(db.supplierDownPayments.filter(x=>x.date===date),'amount')}
function paidFor(refType,refId){return sum(db.payments.filter(p=>p.refType===refType&&p.refId===refId),'amount')}
function cashPaymentsOnDate(date,excludePaymentId=null){return sum(db.payments.filter(p=>p.date===date&&p.method==='cash'&&p.id!==excludePaymentId),'amount')}
function cashPurchaseOutOnDate(date){return sum(db.purchases.filter(p=>p.date===date&&p.paymentType==='cash').map(p=>({amount:Math.max(0,purchaseTotal(p)-dpAppliedForPurchase(p.id))})))}
function dailyCashBase(date){return sum(db.ownerCash.filter(x=>x.date===date))-sum(db.dailyExpenses.filter(x=>x.date===date))-cashPurchaseOutOnDate(date)-downPaymentOutOnDate(date)}
function dailyCashBalance(date,excludePaymentId=null){return dailyCashBase(date)-cashPaymentsOnDate(date,excludePaymentId)}
function validateCashPayment(date,amount,excludePaymentId=null){const available=dailyCashBalance(date,excludePaymentId);if(amount>available){showAlert(`Saldo kas tanggal ${formatDate(date)} tidak cukup. Sisa kas tersedia ${fmt(available)}.`, 'error');return false;}return true;}
function purchaseTotal(p){return Number(p.amount ?? (Number(p.qty||0)*Number(p.unitPrice||0)))}
function statusFor(total,paid){if(paid<=0)return 'unpaid';if(paid<total)return 'partial';return 'paid'}
function badge(status){const map={paid:['Lunas','badge-paid'],unpaid:['Belum Dibayar','badge-unpaid'],partial:['Dibayar Sebagian','badge-partial']};const [t,c]=map[status]||[status,''];return `<span class="badge ${c}">${t}</span>`}
function formatDate(s){return parseDate(s).toLocaleDateString('id-ID',{day:'2-digit',month:'short',year:'numeric'})}
function table(headers,rows){if(!rows.length)return '<div class="empty-state">Belum ada data.</div>';return `<div class="table-wrap"><table><thead><tr>${headers.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${rows.join('')}</tbody></table></div>`}
function latestSort(items){return [...(items||[])].sort((a,b)=>{const d=String(b.date||b.createdAt||'').localeCompare(String(a.date||a.createdAt||''));if(d!==0)return d;return String(b.createdAt||'').localeCompare(String(a.createdAt||''));})}
function alphaSort(items,key='name'){return [...(items||[])].sort((a,b)=>String(a[key]||'').localeCompare(String(b[key]||''),'id-ID'))}
function paginationControls(key,total,page,max){if(total<=PAGE_SIZE)return '';const start=(page-1)*PAGE_SIZE+1,end=Math.min(page*PAGE_SIZE,total);return `<div class="pagination"><span>Menampilkan ${start}-${end} dari ${total} data</span><div><button class="btn btn-small btn-secondary" onclick="changeTablePage('${key}',-1)" ${page<=1?'disabled':''}>Prev</button><button class="btn btn-small btn-secondary" onclick="changeTablePage('${key}',1)" ${page>=max?'disabled':''}>Next</button></div></div>`}
function pagedTable(key,headers,items,rowFn,sorter=latestSort){const sorted=sorter(items);const total=sorted.length;if(!total)return table(headers,[]);const max=Math.max(1,Math.ceil(total/PAGE_SIZE));let page=pageState[key]||1;if(page>max)page=max;if(page<1)page=1;pageState[key]=page;const rows=sorted.slice((page-1)*PAGE_SIZE,page*PAGE_SIZE).map(rowFn);return table(headers,rows)+paginationControls(key,total,page,max)}
function pagedCards(key,items,cardFn,sorter=latestSort){const sorted=sorter(items);const total=sorted.length;if(!total)return '<div class="empty-state">Tidak ada tagihan yang perlu dibayar.</div>';const max=Math.max(1,Math.ceil(total/PAGE_SIZE));let page=pageState[key]||1;if(page>max)page=max;if(page<1)page=1;pageState[key]=page;return sorted.slice((page-1)*PAGE_SIZE,page*PAGE_SIZE).map(cardFn).join('')+paginationControls(key,total,page,max)}
window.changeTablePage=(key,delta)=>{pageState[key]=(pageState[key]||1)+delta;renderAll();};
function showAlert(msg,type='success'){const a=document.getElementById('alertArea');a.innerHTML=`<div class="alert alert-${type}">${msg}</div>`;setTimeout(()=>a.innerHTML='',4000)}
function showAuthMessage(msg,type='error'){document.getElementById('authMessage').innerHTML=`<div class="auth-${type}">${msg}</div>`}
function setDefaultDates(){
  const currentDate=getTodayLocal();
  document.querySelectorAll('input[type=date]').forEach(i=>{
    if(i.id==='cycleDatePicker')return;
    if(!i.value)i.value=currentDate;
  });
  document.getElementById('cycleDatePicker').value=selectedDate;
}
function mapRows(rows, mapper){return (rows||[]).map(mapper)}
function normalizeData(data){
  db.suppliers=mapRows(data.suppliers,r=>({id:r.id,createdAt:r.created_at,name:r.name,productType:r.product_type,phone:r.phone,bankName:r.bank_name,accountNumber:r.account_number,accountHolder:r.account_holder,status:r.status,note:r.note}));
  db.ownerCash=mapRows(data.owner_cash,r=>({id:r.id,createdAt:r.created_at,date:r.transaction_date,amount:Number(r.amount),receiver:r.receiver,note:r.note}));
  db.dailyExpenses=mapRows(data.daily_expenses,r=>({id:r.id,createdAt:r.created_at,date:r.transaction_date,category:r.category,amount:Number(r.amount),note:r.note}));
  db.dailyClosings=mapRows(data.daily_closings,r=>({id:r.id,createdAt:r.created_at,date:r.closing_date,physicalCash:Number(r.physical_cash),expectedCash:Number(r.expected_cash),difference:Number(r.difference),returnedTo:r.returned_to,note:r.note}));
  db.purchases=mapRows(data.purchases,r=>({id:r.id,createdAt:r.created_at,date:r.transaction_date,supplierId:r.supplier_id,amount:Number(r.amount ?? (Number(r.qty||0)*Number(r.unit_price||0))),paymentType:r.payment_type,paymentMethod:r.payment_method,note:r.note,receiptPath:r.receipt_path}));
  db.weeklyExpenses=mapRows(data.weekly_expenses,r=>({id:r.id,createdAt:r.created_at,date:r.transaction_date,category:r.category,amount:Number(r.amount),note:r.note,status:r.initial_status,paymentMethod:r.payment_method}));
  db.payments=mapRows(data.payments,r=>({id:r.id,createdAt:r.created_at,refType:r.ref_type,refId:r.ref_id,amount:Number(r.amount),method:r.method,date:r.payment_date}));
  db.supplierDownPayments=mapRows(data.supplier_down_payments,r=>({id:r.id,createdAt:r.created_at,date:r.transaction_date,supplierId:r.supplier_id,amount:Number(r.amount),note:r.note,appliedPurchaseId:r.applied_purchase_id,appliedAmount:Number(r.applied_amount||0)}));
}
async function loadAll(){
  if(!sb)return;
  const names=['suppliers','owner_cash','daily_expenses','daily_closings','purchases','weekly_expenses','payments','supplier_down_payments'];
  const results=await Promise.all(names.map(name=>sb.from(name).select('*').order('created_at',{ascending:true})));
  const failed=results.find(r=>r.error); if(failed) throw failed.error;
  const data={}; names.forEach((n,i)=>data[n]=results[i].data);
  normalizeData(data); renderAll();
}
async function insertRow(tableName,payload,msg){const {error}=await sb.from(tableName).insert(payload);if(error)throw error;await loadAll();showAlert(msg)}
async function deleteRow(tableName,id){const {error}=await sb.from(tableName).delete().eq('id',id);if(error)throw error;await loadAll()}
async function updateRow(tableName,id,payload){const {error}=await sb.from(tableName).update(payload).eq('id',id);if(error)throw error;}
async function recalcClosing(date){const closing=db.dailyClosings.find(x=>x.date===date);if(!closing)return;const expected=dailyCashBalance(date);await updateRow('daily_closings',closing.id,{expected_cash:expected,difference:Number(closing.physicalCash)-expected});}
async function handle(action){try{await action()}catch(err){console.error(err);showAlert(err.message||'Terjadi kesalahan.','error')}}

function renderAll(){renderCycleLabel();renderCashBalanceHeader();renderDashboard();renderDailyCash();renderDailyCashFlow();renderDailyTransactionTables();renderSuppliers();renderPurchaseOptions();renderPurchaseDpOptions();renderSupplierDownPayments();renderPurchases();renderWeeklyExpenses();renderSaturdayPayments();renderPaymentHistory();renderSupplierReport();renderReport();applyRoleUi();setDefaultDates()}
function renderCycleLabel(){const c=getCycle(selectedDate);document.getElementById('cycleLabel').textContent=`Siklus ${formatDate(c.start)} - ${formatDate(c.end)}`}
function renderCashBalanceHeader(){const box=document.getElementById('cashBalanceHeader');if(!box)return;const d=selectedDate||getTodayLocal();const balance=dailyCashBalance(d);const label=d===getTodayLocal()?'Sisa Kas Hari Ini':'Sisa Kas Tanggal Dipilih';box.innerHTML=`<span>${label}</span><strong class="${balance<0?'negative':''}">${fmt(balance)}</strong><small>${formatDate(d)}</small>`}
function renderDashboard(){const {c,ownerCash,dailyExpenses,purchases,weeklyExpenses,supplierDownPayments}=cycleData();const cashPurch=purchases.filter(p=>p.paymentType==='cash');const tempo=purchases.filter(p=>p.paymentType==='tempo');const cashPurchaseTotal=sum(cashPurch.map(p=>({amount:Math.max(0,purchaseTotal(p)-dpAppliedForPurchase(p.id))})));const dpTotal=sum(supplierDownPayments);const weeklyPaidNow=weeklyExpenses.filter(x=>x.status==='paid');const directOut=sum(dailyExpenses)+dpTotal+cashPurchaseTotal+sum(weeklyPaidNow);const supplierTempoTotal=sum(tempo.map(p=>({amount:purchaseTotal(p)})));const supplierTempoPaid=sum(tempo.map(p=>({amount:purchasePaidFor(p.id)})));const weeklyUnpaidTotal=sum(weeklyExpenses.filter(x=>x.status==='unpaid'));const weeklyPaid=sum(weeklyExpenses.map(x=>({amount:paidFor('weekly',x.id)})));const outstanding=Math.max(0,supplierTempoTotal-supplierTempoPaid)+Math.max(0,weeklyUnpaidTotal-weeklyPaid);const ownerTotal=sum(ownerCash);const returnTotal=sum(db.dailyClosings.filter(x=>inCycle(x.date,c)),'physicalCash');const metrics=[['Dana dari Owner',fmt(ownerTotal),''],['Pengeluaran Langsung',fmt(directOut),''],['Tagihan Belum Lunas',fmt(outstanding),outstanding?'warning':''],['Dikembalikan ke Owner',fmt(returnTotal),'']];document.getElementById('dashboardMetrics').innerHTML=metrics.map(m=>`<div class="metric ${m[2]}"><span>${m[0]}</span><strong>${m[1]}</strong></div>`).join('');const breakdown={'Pengeluaran Harian':sum(dailyExpenses),'DP Supplier':dpTotal,'Pembelian Supplier Cash':cashPurchaseTotal,'Pembelian Supplier Tempo':supplierTempoTotal,'Pengeluaran Mingguan':sum(weeklyExpenses)};document.getElementById('expenseBreakdown').innerHTML=`<div class="summary-list">${Object.entries(breakdown).map(([k,v])=>`<div class="summary-row"><span>${k}</span><strong>${fmt(v)}</strong></div>`).join('')}</div>`;const days=[];for(let i=0;i<6;i++){const d=parseDate(c.start);d.setDate(d.getDate()+i);const ds=iso(d);const incoming=sum(ownerCash.filter(x=>x.date===ds));const spent=sum(dailyExpenses.filter(x=>x.date===ds))+downPaymentOutOnDate(ds)+cashPurchaseOutOnDate(ds)+cashPaymentsOnDate(ds);const closing=db.dailyClosings.find(x=>x.date===ds);days.push(`<tr><td>${formatDate(ds)}</td><td class="amount">${fmt(incoming)}</td><td class="amount">${fmt(spent)}</td><td>${closing?badge(closing.difference===0?'paid':'partial'):'<span class="badge badge-unpaid">Belum ditutup</span>'}</td></tr>`)}document.getElementById('dailyStatus').innerHTML=table(['Tanggal','Kas Masuk','Terpakai','Status'],days);const unpaidRows=[];tempo.forEach(p=>{const total=purchaseTotal(p),paid=purchasePaidFor(p.id),remain=total-paid;if(remain>0)unpaidRows.push(`<tr><td>${supplierName(p.supplierId)}</td><td>${p.note||'-'}</td><td class="amount">${fmt(total)}</td><td class="amount">${fmt(remain)}</td></tr>`)});weeklyExpenses.forEach(x=>{const paid=x.status==='paid'?x.amount:paidFor('weekly',x.id),remain=x.amount-paid;if(remain>0)unpaidRows.push(`<tr><td>${x.category}</td><td>${x.note}</td><td class="amount">${fmt(x.amount)}</td><td class="amount">${fmt(remain)}</td></tr>`)});document.getElementById('unpaidSummary').innerHTML=table(['Penerima/Kategori','Keterangan','Total','Sisa'],unpaidRows)}
function renderDailyCash(){const {c,ownerCash,dailyExpenses}=cycleData();const rows=[];for(let i=0;i<6;i++){const d=parseDate(c.start);d.setDate(d.getDate()+i);const ds=iso(d);const incoming=sum(ownerCash.filter(x=>x.date===ds));const exp=sum(dailyExpenses.filter(x=>x.date===ds))+downPaymentOutOnDate(ds)+cashPurchaseOutOnDate(ds)+cashPaymentsOnDate(ds);const expected=incoming-exp;const closing=db.dailyClosings.find(x=>x.date===ds);const diff=closing?Number(closing.physicalCash)-expected:null;const action=closing?`<div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="editDailyClosing('${closing.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteRecord('daily_closings','${closing.id}')">Buka Kembali</button>`:''}</div>`:'-';rows.push(`<tr><td>${formatDate(ds)}</td><td class="amount">${fmt(incoming)}</td><td class="amount">${fmt(exp)}</td><td class="amount">${fmt(expected)}</td><td class="amount">${closing?fmt(closing.physicalCash):'-'}</td><td class="amount ${diff<0?'negative':diff>0?'positive':''}">${diff===null?'-':fmt(diff)}</td><td>${closing?'<span class="badge badge-paid">Ditutup</span>':'<span class="badge badge-unpaid">Terbuka</span>'}</td><td>${action}</td></tr>`)}document.getElementById('dailyCashTable').innerHTML=table(['Tanggal','Kas Owner','Pengeluaran + Bayaran','Sisa Sistem','Kas Fisik','Selisih','Status','Aksi'],rows)}
function renderDailyCashFlow(){
  const date=dailyCashFlowDate||selectedDate||getTodayLocal();
  const form=document.getElementById('dailyCashFlowFilter');
  const metricBox=document.getElementById('dailyCashFlowMetrics');
  const tableBox=document.getElementById('dailyCashFlowTable');
  if(!form||!metricBox||!tableBox)return;
  form.elements.date.value=date;
  const rows=[];
  db.ownerCash.filter(x=>x.date===date).forEach(x=>rows.push({createdAt:x.createdAt,type:'debit',desc:`Uang masuk dari owner${x.receiver?` - diterima ${x.receiver}`:''}`,note:x.note||'-',debit:Number(x.amount),credit:0}));
  db.dailyExpenses.filter(x=>x.date===date).forEach(x=>rows.push({createdAt:x.createdAt,type:'credit',desc:`Pengeluaran Harian - ${x.category}`,note:x.note||'-',debit:0,credit:Number(x.amount)}));
  db.supplierDownPayments.filter(x=>x.date===date).forEach(x=>rows.push({createdAt:x.createdAt,type:'credit',desc:`DP Supplier - ${supplierName(x.supplierId)}`,note:x.note||'-',debit:0,credit:Number(x.amount)}));
  db.purchases.filter(p=>p.date===date&&p.paymentType==='cash').forEach(p=>rows.push({createdAt:p.createdAt,type:'credit',desc:`Barang Masuk Cash - ${supplierName(p.supplierId)}`,note:p.note||'-',debit:0,credit:Math.max(0,purchaseTotal(p)-dpAppliedForPurchase(p.id))}));
  db.payments.filter(p=>p.date===date&&p.method==='cash').forEach(p=>rows.push({createdAt:p.createdAt,type:'credit',desc:`Bayaran Sabtu - ${paymentTitle(p)}`,note:'Pembayaran cash',debit:0,credit:Number(p.amount)}));
  const sorted=rows.sort((a,b)=>String(a.createdAt||'').localeCompare(String(b.createdAt||'')));
  let saldo=0;
  const rowHtml=sorted.map(r=>{saldo+=r.debit-r.credit;return `<tr><td>${formatDate(date)}</td><td>${r.desc}</td><td>${r.note}</td><td class="amount positive">${r.debit?fmt(r.debit):'-'}</td><td class="amount negative">${r.credit?fmt(r.credit):'-'}</td><td class="amount ${saldo<0?'negative':''}">${fmt(saldo)}</td></tr>`});
  const totalDebit=sum(sorted.map(r=>({amount:r.debit}))), totalCredit=sum(sorted.map(r=>({amount:r.credit}))), finalSaldo=totalDebit-totalCredit;
  metricBox.innerHTML=[['Total Debit',fmt(totalDebit),''],['Total Credit',fmt(totalCredit),totalCredit?'warning':''],['Saldo Akhir',fmt(finalSaldo),finalSaldo<0?'warning':'']].map(m=>`<div class="metric ${m[2]}"><span>${m[0]}</span><strong>${m[1]}</strong></div>`).join('');
  tableBox.innerHTML=table(['Tanggal','Keterangan','Catatan','Debit','Credit','Saldo'],rowHtml);
}

function renderDailyTransactionTables(){const {ownerCash,dailyExpenses}=cycleData();document.getElementById('ownerCashTable').innerHTML=pagedTable('ownerCashTable',['Tanggal','Nominal','Diterima Oleh','Keterangan','Aksi'],ownerCash,x=>`<tr><td>${formatDate(x.date)}</td><td class="amount">${fmt(x.amount)}</td><td>${x.receiver}</td><td>${x.note||'-'}</td><td><div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="editOwnerCash('${x.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteRecord('owner_cash','${x.id}')">Hapus</button>`:''}</div></td></tr>`);document.getElementById('dailyExpenseTable').innerHTML=pagedTable('dailyExpenseTable',['Tanggal','Kategori','Nominal','Keterangan','Aksi'],dailyExpenses,x=>`<tr><td>${formatDate(x.date)}</td><td>${x.category}</td><td class="amount">${fmt(x.amount)}</td><td>${x.note||'-'}</td><td><div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="editDailyExpense('${x.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteRecord('daily_expenses','${x.id}')">Hapus</button>`:''}</div></td></tr>`)}
function renderSuppliers(){document.getElementById('supplierTable').innerHTML=pagedTable('supplierTable',['Supplier','No. HP','Rekening','Status','Aksi'],db.suppliers,s=>`<tr><td><strong>${s.name}</strong><br><small>${s.productType}</small></td><td>${s.phone}</td><td>${s.accountNumber?`${s.bankName||'-'}<br>${s.accountNumber}<br><small>${s.accountHolder||''}</small>`:'Cash saja'}</td><td>${s.status}</td><td><div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="openSupplierReport('${s.id}')">Transaksi</button><button class="btn btn-small btn-secondary" onclick="editSupplier('${s.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteSupplier('${s.id}')">Hapus</button>`:''}</div></td></tr>`,items=>alphaSort(items,'name'))}
function supplierSearchLabel(s){return `${s.name}${s.productType?` - ${s.productType}`:''}`}
function syncPurchaseSupplierId(){const input=document.getElementById('purchaseSupplierSearch'),hidden=document.getElementById('purchaseSupplierId');if(!input||!hidden)return;const typed=input.value.trim().toLowerCase();const match=db.suppliers.find(s=>s.status==='Aktif'&&(supplierSearchLabel(s).toLowerCase()===typed||s.name.toLowerCase()===typed));if(match){hidden.value=match.id;input.value=supplierSearchLabel(match)}else hidden.value='';renderPurchaseDpOptions()}
function renderPurchaseOptions(){const lists=[document.getElementById('purchaseSupplierOptions'),document.getElementById('dpSupplierOptions')].filter(Boolean);lists.forEach(list=>{list.innerHTML=db.suppliers.filter(s=>s.status==='Aktif').map(s=>`<option value="${supplierSearchLabel(s).replace(/"/g,'&quot;')}"></option>`).join('')});syncPurchaseSupplierId();syncDpSupplierId();}

function renderPurchaseDpOptions(){
  const select=document.getElementById('purchaseDownPaymentSelect');
  if(!select)return;
  const supplierId=document.getElementById('purchaseSupplierId')?.value;
  const current=select.value;
  const options=['<option value="">Tidak memakai DP</option>'];
  if(supplierId){
    openDownPaymentsForSupplier(supplierId).forEach(d=>options.push(`<option value="${d.id}">${formatDate(d.date)} - ${fmt(d.amount)} - ${(d.note||'DP').replace(/</g,'&lt;')}</option>`));
  }
  select.innerHTML=options.join('');
  if([...select.options].some(o=>o.value===current))select.value=current;
}
function renderSupplierDownPayments(){
  const box=document.getElementById('supplierDownPaymentTable');
  if(!box)return;
  const {supplierDownPayments}=cycleData();
  box.innerHTML=pagedTable('supplierDownPaymentTable',['Tanggal','Supplier','Nominal DP','Keterangan','Status','Aksi'],supplierDownPayments,d=>{
    const applied=d.appliedPurchaseId?'<span class="badge badge-paid">Sudah Dipakai</span>':'<span class="badge badge-unpaid">Belum Dipakai</span>';
    const action=`<div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="editSupplierDownPayment('${d.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteRecord('supplier_down_payments','${d.id}')">Hapus</button>`:''}</div>`;
    return `<tr><td>${formatDate(d.date)}</td><td>${supplierName(d.supplierId)}</td><td class="amount">${fmt(d.amount)}</td><td>${d.note||'-'}</td><td>${applied}</td><td>${action}</td></tr>`;
  });
}
function syncDpSupplierId(){const input=document.getElementById('dpSupplierSearch'),hidden=document.getElementById('dpSupplierId');if(!input||!hidden)return;const val=input.value.trim().toLowerCase();const match=db.suppliers.find(s=>supplierSearchLabel(s).toLowerCase()===val||s.name.toLowerCase()===val);if(match){hidden.value=match.id;input.value=supplierSearchLabel(match)}else hidden.value=''}
function renderPurchases(){const {purchases}=cycleData();document.getElementById('purchaseTable').innerHTML=pagedTable('purchaseTable',['Tanggal','Supplier','Keterangan','Jenis','Total','DP','Sisa Bayar','Status','Nota','Aksi'],purchases,p=>{const total=purchaseTotal(p),dp=dpAppliedForPurchase(p.id),paid=p.paymentType==='cash'?total:purchasePaidFor(p.id),st=statusFor(total,paid);const receipt=p.receiptPath?`<button class="btn btn-small btn-secondary" onclick="openReceipt('${p.receiptPath}')">Lihat Nota</button>`:'-';return `<tr><td>${formatDate(p.date)}</td><td>${supplierName(p.supplierId)}</td><td>${p.note||'-'}</td><td>${p.paymentType==='cash'?'Cash':'Tempo'}</td><td class="amount">${fmt(total)}</td><td class="amount">${dp?fmt(dp):'-'}</td><td class="amount">${fmt(Math.max(0,total-dp))}</td><td>${badge(st)}</td><td>${receipt}</td><td><div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="editPurchase('${p.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteRecord('purchases','${p.id}')">Hapus</button>`:''}</div></td></tr>`})}
function renderSupplierReport(){
  const title=document.getElementById('supplierReportTitle'),subtitle=document.getElementById('supplierReportSubtitle'),metrics=document.getElementById('supplierReportMetrics'),tableBox=document.getElementById('supplierReportTable'),form=document.getElementById('supplierReportFilter');
  if(!title||!subtitle||!metrics||!tableBox||!form)return;
  const supplier=db.suppliers.find(s=>s.id===supplierReportState.supplierId);
  if(!supplier){title.textContent='Laporan Transaksi Supplier';subtitle.textContent='Pilih supplier dari menu Data Supplier.';metrics.innerHTML='';tableBox.innerHTML='<div class="empty-state">Belum ada supplier yang dipilih.</div>';return;}
  const c=getCycle(selectedDate);
  const from=supplierReportState.from||c.start;
  const to=supplierReportState.to||c.end;
  form.elements.from.value=from;
  form.elements.to.value=to;
  title.textContent=`Laporan Transaksi ${supplier.name}`;
  subtitle.textContent=`${supplier.productType||'-'} • Periode ${formatDate(from)} - ${formatDate(to)}`;
  const rows=db.purchases.filter(p=>p.supplierId===supplier.id&&p.date>=from&&p.date<=to);
  const total=sum(rows.map(p=>({amount:purchaseTotal(p)})));
  const paid=sum(rows.map(p=>({amount:p.paymentType==='cash'?purchaseTotal(p):paidFor('purchase',p.id)})));
  const unpaid=Math.max(0,total-paid);
  const tempoCount=rows.filter(p=>p.paymentType==='tempo').length;
  metrics.innerHTML=[['Total Transaksi',`${rows.length} nota`,''],['Total Pembelian',fmt(total),''],['Sudah Dibayar',fmt(paid),''],['Sisa Tagihan',fmt(unpaid),unpaid?'warning':''],['Transaksi Tempo',`${tempoCount} nota`,'']].map(m=>`<div class="metric ${m[2]}"><span>${m[0]}</span><strong>${m[1]}</strong></div>`).join('');
  tableBox.innerHTML=pagedTable('supplierReportTable',['Tanggal','Keterangan','Jenis','Total','Sudah Dibayar','Sisa','Status','Nota'],rows,p=>{const total=purchaseTotal(p),paid=p.paymentType==='cash'?total:purchasePaidFor(p.id),remain=Math.max(0,total-paid),st=statusFor(total,paid);const receipt=p.receiptPath?`<button class="btn btn-small btn-secondary" onclick="openReceipt('${p.receiptPath}')" type="button">Lihat Nota</button>`:'-';return `<tr><td>${formatDate(p.date)}</td><td>${p.note||'-'}</td><td>${p.paymentType==='cash'?'Cash':'Tempo'}</td><td class="amount">${fmt(total)}</td><td class="amount">${fmt(paid)}</td><td class="amount">${fmt(remain)}</td><td>${badge(st)}</td><td>${receipt}</td></tr>`});
}

function renderWeeklyExpenses(){const {weeklyExpenses}=cycleData();document.getElementById('weeklyExpenseTable').innerHTML=pagedTable('weeklyExpenseTable',['Tanggal','Kategori','Keterangan','Nominal','Status','Aksi'],weeklyExpenses,x=>{const paid=x.status==='paid'?x.amount:paidFor('weekly',x.id);return `<tr><td>${formatDate(x.date)}</td><td>${x.category}</td><td>${x.note}</td><td class="amount">${fmt(x.amount)}</td><td>${badge(statusFor(x.amount,paid))}</td><td><div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="editWeeklyExpense('${x.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteRecord('weekly_expenses','${x.id}')">Hapus</button>`:''}</div></td></tr>`})}
function renderSaturdayPayments(){
  const {purchases,weeklyExpenses}=cycleData();
  const supplierGroups=new Map();
  purchases.filter(p=>p.paymentType==='tempo').forEach(p=>{
    const total=purchaseTotal(p),paid=purchasePaidFor(p.id),remain=total-paid;
    if(remain<=0)return;
    const supplier=db.suppliers.find(s=>s.id===p.supplierId);
    const key=p.supplierId||'unknown';
    if(!supplierGroups.has(key))supplierGroups.set(key,{date:p.date,createdAt:p.createdAt,refType:'supplierGroup',supplierId:key,title:supplierName(p.supplierId),supplier,remain:0,notes:[]});
    const group=supplierGroups.get(key);
    group.remain+=remain;
    if(String(p.date||'')>String(group.date||''))group.date=p.date;
    if(String(p.createdAt||'')>String(group.createdAt||''))group.createdAt=p.createdAt;
    group.notes.push({id:p.id,date:p.date,desc:p.note||'-',total,paid,remain,receiptPath:p.receiptPath});
  });
  const items=[...supplierGroups.values()];
  weeklyExpenses.filter(x=>x.status==='unpaid').forEach(x=>{
    const paid=paidFor('weekly',x.id),remain=x.amount-paid;
    if(remain>0)items.push({date:x.date,createdAt:x.createdAt,refType:'weekly',refId:x.id,title:x.category,desc:x.note||'-',remain});
  });
  document.getElementById('saturdayPaymentList').innerHTML=pagedCards('saturdayPaymentList',items,i=>{
    if(i.refType==='supplierGroup'){
      const detailId=`detail-${String(i.supplierId).replace(/[^a-zA-Z0-9_-]/g,'')}`;
      const details=latestSort(i.notes).map(n=>`<tr><td>${formatDate(n.date)}</td><td>${n.desc}</td><td class="amount">${fmt(n.total)}</td><td class="amount">${fmt(n.paid)}</td><td class="amount"><strong>${fmt(n.remain)}</strong></td><td>${n.receiptPath?`<button class="btn btn-small btn-secondary" onclick="openReceipt('${n.receiptPath}')" type="button">Lihat Nota</button>`:'-'}</td></tr>`).join('');
      return `<div class="payment-card payment-group"><div class="payment-card-top"><div><strong>${i.title}</strong><div class="muted">${i.notes.length} nota belum lunas</div></div><div class="amount"><small>Total sisa tagihan</small><br><strong>${fmt(i.remain)}</strong></div></div><button class="btn btn-small btn-secondary" type="button" onclick="togglePaymentGroup('${detailId}')">Lihat Detail Nota</button><div id="${detailId}" class="payment-details hidden">${table(['Tanggal','Keterangan Nota','Total Nota','Sudah Dibayar','Sisa','Nota'],details?details.match(/<tr/g)?.map(()=>'' )||[]:[]).replace('<tbody></tbody>',`<tbody>${details}</tbody>`).replace('<div class="empty-state">Belum ada data.</div>','')}</div><form class="payment-form" onsubmit="submitSupplierPayment(event,'${i.supplierId}',${i.remain})"><input name="amount" type="number" min="1" max="${i.remain}" value="${i.remain}" required><select name="method"><option value="cash">Cash</option>${i.supplier&&!i.supplier.accountNumber?'':`<option value="transfer">Transfer</option>`}</select><input name="date" type="date" value="${getTodayLocal()}" required><button class="btn btn-primary" type="submit">Bayar</button></form></div>`;
    }
    return `<div class="payment-card"><div class="payment-card-top"><div><strong>${i.title}</strong><div class="muted">${i.desc}</div></div><div class="amount"><small>Sisa tagihan</small><br><strong>${fmt(i.remain)}</strong></div></div><form class="payment-form" onsubmit="submitPayment(event,'${i.refType}','${i.refId}',${i.remain})"><input name="amount" type="number" min="1" max="${i.remain}" value="${i.remain}" required><select name="method"><option value="cash">Cash</option><option value="transfer">Transfer</option></select><input name="date" type="date" value="${getTodayLocal()}" required><button class="btn btn-primary" type="submit">Bayar</button></form></div>`;
  });
}
function paymentTitle(p){if(p.refType==='purchase'){const x=db.purchases.find(r=>r.id===p.refId);return x?`Supplier: ${supplierName(x.supplierId)}`:'Pembelian supplier';}const x=db.weeklyExpenses.find(r=>r.id===p.refId);return x?x.category:'Beban mingguan'}
function renderPaymentHistory(){const c=getCycle(selectedDate);const payments=db.payments.filter(p=>inCycle(p.date,c));document.getElementById('paymentHistoryTable').innerHTML=pagedTable('paymentHistoryTable',['Tanggal','Pembayaran Untuk','Metode','Nominal','Aksi'],payments,p=>`<tr><td>${formatDate(p.date)}</td><td>${paymentTitle(p)}</td><td>${p.method==='transfer'?'Transfer':'Cash'}</td><td class="amount">${fmt(p.amount)}</td><td><div class="action-buttons"><button class="btn btn-small btn-secondary" onclick="editPayment('${p.id}')">Edit</button>${isOwner()?`<button class="btn btn-small btn-danger-outline" onclick="deleteRecord('payments','${p.id}')">Hapus</button>`:''}</div></td></tr>`)}
function renderReport(){const {c,ownerCash,dailyExpenses,purchases,weeklyExpenses,supplierDownPayments}=cycleData();const purchaseCash=purchases.filter(p=>p.paymentType==='cash'),purchaseTempo=purchases.filter(p=>p.paymentType==='tempo');const totalOwner=sum(ownerCash),totalDaily=sum(dailyExpenses),totalDp=sum(supplierDownPayments),totalCashPurchaseCost=sum(purchaseCash.map(p=>({amount:purchaseTotal(p)}))),totalCashPurch=sum(purchaseCash.map(p=>({amount:Math.max(0,purchaseTotal(p)-dpAppliedForPurchase(p.id))}))),totalTempo=sum(purchaseTempo.map(p=>({amount:purchaseTotal(p)}))),totalWeekly=sum(weeklyExpenses),totalCost=totalDaily+totalCashPurchaseCost+totalTempo+totalWeekly,totalPaidTempo=sum(purchaseTempo.map(p=>({amount:purchasePaidFor(p.id)}))),totalPaidWeekly=sum(weeklyExpenses.map(x=>({amount:x.status==='paid'?x.amount:paidFor('weekly',x.id)}))),realCashOut=totalDaily+totalDp+totalCashPurch+sum(db.payments.filter(p=>inCycle(p.date,c)).map(p=>({amount:p.amount}))),outstanding=Math.max(0,totalTempo-totalPaidTempo)+Math.max(0,totalWeekly-totalPaidWeekly);const supplierRows=purchases.map(p=>`<tr><td>${formatDate(p.date)}</td><td>${supplierName(p.supplierId)}</td><td>${p.note||'-'}</td><td>${p.paymentType==='cash'?'Cash':'Tempo'}</td><td class="amount">${fmt(purchaseTotal(p))}</td></tr>`),dailyRows=dailyExpenses.map(x=>`<tr><td>${formatDate(x.date)}</td><td>${x.category}</td><td>${x.note}</td><td class="amount">${fmt(x.amount)}</td></tr>`);document.getElementById('reportContent').innerHTML=`<div class="report-summary"><div class="report-box"><span>Dana dari Owner</span><strong>${fmt(totalOwner)}</strong></div><div class="report-box"><span>Total Biaya Siklus</span><strong>${fmt(totalCost)}</strong></div><div class="report-box"><span>Uang Benar-benar Keluar</span><strong>${fmt(realCashOut)}</strong></div><div class="report-box"><span>Tagihan Belum Lunas</span><strong>${fmt(outstanding)}</strong></div><div class="report-box"><span>Pengeluaran Harian</span><strong>${fmt(totalDaily)}</strong></div><div class="report-box"><span>DP Supplier</span><strong>${fmt(totalDp)}</strong></div><div class="report-box"><span>Pembelian Supplier</span><strong>${fmt(totalCashPurchaseCost+totalTempo)}</strong></div></div><div class="report-section"><h3>Pengeluaran Harian</h3>${table(['Tanggal','Kategori','Keterangan','Nominal'],dailyRows)}</div><div class="report-section"><h3>Pembelian Supplier</h3>${table(['Tanggal','Supplier','Keterangan','Pembayaran','Total'],supplierRows)}</div><div class="report-section"><h3>Pengeluaran Mingguan</h3>${table(['Tanggal','Kategori','Keterangan','Nominal'],weeklyExpenses.map(x=>`<tr><td>${formatDate(x.date)}</td><td>${x.category}</td><td>${x.note}</td><td class="amount">${fmt(x.amount)}</td></tr>`))}</div><div class="report-section"><h3>Catatan Siklus</h3><p>Periode ${formatDate(c.start)} sampai ${formatDate(c.end)}. Total biaya mengikuti tanggal transaksi, sedangkan uang benar-benar keluar mengikuti pembayaran aktual.</p></div>`}

function closeReceiptPreview(){const modal=document.getElementById('receiptModal'),preview=document.getElementById('receiptPreview');if(modal)modal.classList.add('hidden');if(preview)preview.innerHTML='';document.body.style.overflow=''}
window.openReceipt=path=>handle(async()=>{const modal=document.getElementById('receiptModal'),preview=document.getElementById('receiptPreview');preview.innerHTML='<div class="receipt-preview-loading">Memuat nota...</div>';modal.classList.remove('hidden');document.body.style.overflow='hidden';const {data,error}=await sb.storage.from('purchase-receipts').createSignedUrl(path,300);if(error)throw error;const url=data.signedUrl;const ext=(path.split('.').pop()||'').toLowerCase();if(ext==='pdf'){preview.innerHTML=`<iframe src="${url}" title="Preview nota PDF"></iframe>`}else{const img=document.createElement('img');img.alt='Preview nota pembelian';img.src=url;img.onerror=()=>{preview.innerHTML='<div class="receipt-preview-error">Nota tidak dapat ditampilkan.</div>'};preview.innerHTML='';preview.appendChild(img)}});

window.openSupplierReport=id=>{const c=getCycle(selectedDate);supplierReportState={supplierId:id,from:c.start,to:c.end};pageState.supplierReportTable=1;renderSupplierReport();document.querySelectorAll('.nav-item').forEach(x=>x.classList.remove('active'));document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById('supplier-report').classList.add('active');document.getElementById('pageTitle').textContent='Transaksi Supplier';document.querySelector('.sidebar').classList.remove('open')};
window.backToSuppliers=()=>{document.querySelectorAll('.nav-item').forEach(x=>x.classList.remove('active'));const btn=document.querySelector('.nav-item[data-view="suppliers"]');if(btn)btn.classList.add('active');document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById('suppliers').classList.add('active');document.getElementById('pageTitle').textContent='Data Supplier'};
window.editPayment=id=>{const x=db.payments.find(r=>r.id===id);if(!x)return;let max=Infinity;if(x.refType==='purchase'){const p=db.purchases.find(r=>r.id===x.refId);if(p)max=purchaseTotal(p)-paidFor('purchase',p.id)+x.amount}else{const w=db.weeklyExpenses.find(r=>r.id===x.refId);if(w)max=w.amount-paidFor('weekly',w.id)+x.amount}const amount=Number(prompt(`Nominal pembayaran (maksimal ${max}):`,x.amount));if(!amount||amount>max)return showAlert('Nominal pembayaran tidak valid.','error');const method=prompt('Metode: cash atau transfer',x.method);if(method===null||!['cash','transfer'].includes(method.toLowerCase()))return showAlert('Metode harus cash atau transfer.','error');const cleanMethod=method.toLowerCase();const date=prompt('Tanggal pembayaran (YYYY-MM-DD):',x.date);if(!date)return;if(cleanMethod==='cash'&&!validateCashPayment(date,amount,id))return;handle(async()=>{const oldDate=x.date;await updateRow('payments',id,{amount,method:cleanMethod,payment_date:date});await loadAll();await recalcClosing(oldDate);if(date!==oldDate)await recalcClosing(date);await loadAll();showAlert('Pembayaran berhasil diperbarui.')})};
window.editOwnerCash=id=>{const x=db.ownerCash.find(r=>r.id===id);if(!x)return;const date=prompt('Tanggal (YYYY-MM-DD):',x.date);if(!date)return;const amount=Number(prompt('Nominal:',x.amount));if(!amount)return showAlert('Nominal tidak valid.','error');const receiver=prompt('Diterima oleh:',x.receiver);if(receiver===null||!receiver.trim())return;const note=prompt('Keterangan:',x.note||'');if(note===null)return;handle(async()=>{const oldDate=x.date;await updateRow('owner_cash',id,{transaction_date:date,amount,receiver:receiver.trim(),note:note.trim()||null});await loadAll();await recalcClosing(oldDate);if(date!==oldDate)await recalcClosing(date);await loadAll();showAlert('Kas masuk berhasil diperbarui.')})};
window.editDailyExpense=id=>{const x=db.dailyExpenses.find(r=>r.id===id);if(!x)return;const date=prompt('Tanggal (YYYY-MM-DD):',x.date);if(!date)return;const category=prompt('Kategori:',x.category);if(category===null||!category.trim())return;const amount=Number(prompt('Nominal:',x.amount));if(!amount)return showAlert('Nominal tidak valid.','error');const note=prompt('Keterangan:',x.note||'');if(note===null)return;handle(async()=>{const oldDate=x.date;await updateRow('daily_expenses',id,{transaction_date:date,category:category.trim(),amount,note:note.trim()||null});await loadAll();await recalcClosing(oldDate);if(date!==oldDate)await recalcClosing(date);await loadAll();showAlert('Pengeluaran harian berhasil diperbarui.')})};
window.editDailyClosing=id=>{const x=db.dailyClosings.find(r=>r.id===id);if(!x)return;const physical=Number(prompt('Kas fisik saat ditutup:',x.physicalCash));if(physical<0||Number.isNaN(physical))return showAlert('Kas fisik tidak valid.','error');const returnedTo=prompt('Dikembalikan kepada:',x.returnedTo||'');if(returnedTo===null||!returnedTo.trim())return;const note=prompt('Catatan:',x.note||'');if(note===null)return;handle(async()=>{const expected=dailyCashBalance(x.date);await updateRow('daily_closings',id,{physical_cash:physical,expected_cash:expected,difference:physical-expected,returned_to:returnedTo.trim(),note:note.trim()||null});await loadAll();showAlert('Penutupan kas berhasil diperbarui.')})};
window.editSupplier=id=>{const x=db.suppliers.find(r=>r.id===id);if(!x)return;const name=prompt('Nama supplier:',x.name);if(name===null||!name.trim())return;const productType=prompt('Jenis kerajinan/barang:',x.productType||'');if(productType===null||!productType.trim())return;const phone=prompt('Nomor HP:',x.phone||'');if(phone===null||!phone.trim())return;const bankName=prompt('Nama bank (boleh kosong):',x.bankName||'');if(bankName===null)return;const accountNumber=prompt('Nomor rekening (boleh kosong):',x.accountNumber||'');if(accountNumber===null)return;const accountHolder=prompt('Nama pemilik rekening (boleh kosong):',x.accountHolder||'');if(accountHolder===null)return;const status=prompt('Status: Aktif atau Nonaktif',x.status||'Aktif');if(status===null||!['Aktif','Nonaktif'].includes(status))return showAlert('Status harus Aktif atau Nonaktif.','error');const note=prompt('Catatan (boleh kosong):',x.note||'');if(note===null)return;handle(async()=>{await updateRow('suppliers',id,{name:name.trim(),product_type:productType.trim(),phone:phone.trim(),bank_name:bankName.trim()||null,account_number:accountNumber.trim()||null,account_holder:accountHolder.trim()||null,status,note:note.trim()||null});await loadAll();showAlert('Data supplier berhasil diperbarui.')})};
window.editPurchase=id=>{const x=db.purchases.find(r=>r.id===id);if(!x)return;const paid=purchasePaidFor(id);const date=prompt('Tanggal pembelian (YYYY-MM-DD):',x.date);if(!date)return;const supplierText=prompt('Ketik nama supplier persis seperti database:',supplierName(x.supplierId));if(supplierText===null)return;const supplier=db.suppliers.find(s=>s.name.trim().toLowerCase()===supplierText.trim().toLowerCase());if(!supplier)return showAlert('Supplier tidak ditemukan. Ketik nama supplier persis.','error');const amount=Number(prompt(`Jumlah / Total Pembelian (minimal ${paid||1}):`,x.amount));if(!amount||amount<paid)return showAlert('Nominal tidak valid atau lebih kecil dari pembayaran yang sudah tercatat.','error');let paymentType=x.paymentType;if(paid<=0){const pt=prompt('Cara pembayaran: cash atau tempo',x.paymentType);if(pt===null)return;if(!['cash','tempo'].includes(pt.toLowerCase()))return showAlert('Cara pembayaran harus cash atau tempo.','error');paymentType=pt.toLowerCase()}const note=prompt('Keterangan:',x.note||'');if(note===null)return;handle(async()=>{const oldDate=x.date;await updateRow('purchases',id,{transaction_date:date,supplier_id:supplier.id,amount,payment_type:paymentType,note:note.trim()||null});await loadAll();await recalcClosing(oldDate);if(date!==oldDate)await recalcClosing(date);await loadAll();showAlert(paid>0?'Pembelian diperbarui. Cara pembayaran dikunci karena sudah ada pembayaran.':'Pembelian berhasil diperbarui.')})};
window.editWeeklyExpense=id=>{const x=db.weeklyExpenses.find(r=>r.id===id);if(!x)return;const paid=x.status==='paid'?x.amount:paidFor('weekly',id);const date=prompt('Tanggal pencatatan (YYYY-MM-DD):',x.date);if(!date)return;const category=prompt('Kategori:',x.category);if(category===null||!category.trim())return;const amount=Number(prompt(`Nominal (minimal ${paid||1}):`,x.amount));if(!amount||amount<paid)return showAlert('Nominal tidak valid atau lebih kecil dari pembayaran yang sudah tercatat.','error');const note=prompt('Keterangan:',x.note||'');if(note===null)return;let status=x.status;if(paid<=0){const st=prompt('Status awal: unpaid atau paid',x.status);if(st===null)return;if(!['unpaid','paid'].includes(st.toLowerCase()))return showAlert('Status harus unpaid atau paid.','error');status=st.toLowerCase()}handle(async()=>{await updateRow('weekly_expenses',id,{transaction_date:date,category:category.trim(),amount,note:note.trim()||null,initial_status:status});await loadAll();showAlert(paid>0?'Beban mingguan diperbarui. Status dikunci karena sudah ada pembayaran.':'Beban mingguan berhasil diperbarui.')})};

window.editSupplierDownPayment=id=>{const x=db.supplierDownPayments.find(r=>r.id===id);if(!x)return;if(x.appliedPurchaseId)return showAlert('DP yang sudah dipakai tidak bisa diedit. Hapus atau edit Barang Masuk terkait jika perlu.','error');const date=prompt('Tanggal DP (YYYY-MM-DD):',x.date);if(!date)return;const supplierText=prompt('Ketik nama supplier persis seperti database:',supplierName(x.supplierId));if(supplierText===null)return;const supplier=db.suppliers.find(s=>s.name.trim().toLowerCase()===supplierText.trim().toLowerCase());if(!supplier)return showAlert('Supplier tidak ditemukan.','error');const amount=Number(prompt('Nominal DP:',x.amount));if(!amount||amount<=0)return showAlert('Nominal tidak valid.','error');const note=prompt('Keterangan DP:',x.note||'');if(note===null)return;const oldDate=x.date;const available=dailyCashBalance(date)+(date===oldDate?Number(x.amount):0);if(amount>available)return showAlert(`Saldo kas tanggal ${formatDate(date)} tidak cukup. Sisa kas tersedia ${fmt(available)}.`, 'error');handle(async()=>{await updateRow('supplier_down_payments',id,{transaction_date:date,supplier_id:supplier.id,amount,note:note.trim()||null});await loadAll();await recalcClosing(oldDate);if(date!==oldDate)await recalcClosing(date);await loadAll();showAlert('DP supplier berhasil diperbarui.')})};
window.deleteRecord=(tableName,id)=>{if(!isOwner())return showAlert('Hanya owner yang dapat menghapus data.','error');if(confirm(tableName==='daily_closings'?'Buka kembali kas harian ini?':'Hapus data ini?'))handle(async()=>{let affectedDate=null;if(tableName==='owner_cash')affectedDate=db.ownerCash.find(x=>x.id===id)?.date;if(tableName==='daily_expenses')affectedDate=db.dailyExpenses.find(x=>x.id===id)?.date;if(tableName==='purchases')affectedDate=db.purchases.find(x=>x.id===id)?.date;if(tableName==='payments')affectedDate=db.payments.find(x=>x.id===id)?.date;if(tableName==='supplier_down_payments')affectedDate=db.supplierDownPayments.find(x=>x.id===id)?.date;if(tableName==='purchases'||tableName==='weekly_expenses')await sb.from('payments').delete().eq('ref_id',id);if(tableName==='purchases'){const p=db.purchases.find(x=>x.id===id);await sb.from('supplier_down_payments').update({applied_purchase_id:null,applied_amount:0}).eq('applied_purchase_id',id);if(p?.receiptPath)await sb.storage.from('purchase-receipts').remove([p.receiptPath]);}await deleteRow(tableName,id);if(affectedDate){await recalcClosing(affectedDate);await loadAll();}showAlert(tableName==='daily_closings'?'Kas harian berhasil dibuka kembali.':'Data berhasil dihapus.')})};
window.deleteSupplier=id=>{if(!isOwner())return showAlert('Hanya owner yang dapat menghapus supplier.','error');if(db.purchases.some(p=>p.supplierId===id))return showAlert('Supplier sudah digunakan dan tidak dapat dihapus.','error');if(confirm('Hapus supplier ini?'))handle(async()=>{await deleteRow('suppliers',id);showAlert('Supplier berhasil dihapus.')})};
window.submitPayment=(e,refType,refId,max)=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));const amount=Number(f.amount);if(amount<=0||amount>max)return showAlert('Nominal pembayaran tidak valid.','error');if(f.method==='cash'&&!validateCashPayment(f.date,amount))return;handle(async()=>{const {error}=await sb.from('payments').insert({ref_type:refType,ref_id:refId,amount,method:f.method,payment_date:f.date});if(error)throw error;await loadAll();await recalcClosing(f.date);await loadAll();showAlert('Pembayaran berhasil dicatat.')})};
window.togglePaymentGroup=id=>{const el=document.getElementById(id);if(el)el.classList.toggle('hidden')};
window.submitSupplierPayment=(e,supplierId,max)=>{
  e.preventDefault();
  const f=Object.fromEntries(new FormData(e.target));
  let amount=Number(f.amount);
  if(amount<=0||amount>max)return showAlert('Nominal pembayaran tidak valid.','error');
  if(f.method==='cash'&&!validateCashPayment(f.date,amount))return;
  const {purchases}=cycleData();
  const targets=latestSort(purchases.filter(p=>p.paymentType==='tempo'&&p.supplierId===supplierId).map(p=>({purchase:p,date:p.date,createdAt:p.createdAt,remain:purchaseTotal(p)-purchasePaidFor(p.id)}))).reverse().filter(x=>x.remain>0);
  handle(async()=>{
    for(const t of targets){
      if(amount<=0)break;
      const pay=Math.min(amount,t.remain);
      await sb.from('payments').insert({ref_type:'purchase',ref_id:t.purchase.id,amount:pay,method:f.method,payment_date:f.date});
      amount-=pay;
    }
    await loadAll();
    await recalcClosing(f.date);
    await loadAll();
    showAlert('Pembayaran supplier berhasil dicatat.');
  });
};

function bindForms(){
  document.querySelectorAll('form').forEach(form=>form.addEventListener('reset',()=>setTimeout(setDefaultDates,0)));
  setDefaultDates();
  document.getElementById('ownerCashForm').addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));handle(async()=>{await insertRow('owner_cash',{transaction_date:f.date,amount:Number(f.amount),receiver:f.receiver,note:f.note||null},'Kas dari owner berhasil dicatat.');e.target.reset()})});
  document.getElementById('dailyExpenseForm').addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));handle(async()=>{await insertRow('daily_expenses',{transaction_date:f.date,category:f.category,amount:Number(f.amount),note:f.note},'Pengeluaran harian berhasil dicatat.');e.target.reset()})});
  document.getElementById('dailyClosingForm').addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));handle(async()=>{if(db.dailyClosings.some(x=>x.date===f.date))throw new Error('Kas pada tanggal tersebut sudah ditutup.');const expected=dailyCashBalance(f.date),physical=Number(f.physicalCash);await insertRow('daily_closings',{closing_date:f.date,physical_cash:physical,expected_cash:expected,difference:physical-expected,returned_to:f.returnedTo,note:f.note||null},physical===expected?'Kas harian ditutup dan sisa dikembalikan.':'Kas ditutup dengan selisih.');e.target.reset()})});
  document.getElementById('supplierForm').addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));handle(async()=>{await insertRow('suppliers',{name:f.name,product_type:f.productType,phone:f.phone,bank_name:f.bankName||null,account_number:f.accountNumber||null,account_holder:f.accountHolder||null,status:f.status,note:f.note||null},'Supplier berhasil ditambahkan.');e.target.reset()})});
  const supplierSearch=document.getElementById('purchaseSupplierSearch');
  if(supplierSearch){supplierSearch.addEventListener('input',syncPurchaseSupplierId);supplierSearch.addEventListener('change',syncPurchaseSupplierId);supplierSearch.addEventListener('blur',syncPurchaseSupplierId)}
  const dpSupplierSearch=document.getElementById('dpSupplierSearch');
  if(dpSupplierSearch){dpSupplierSearch.addEventListener('input',syncDpSupplierId);dpSupplierSearch.addEventListener('change',syncDpSupplierId);dpSupplierSearch.addEventListener('blur',syncDpSupplierId)}
  const dpForm=document.getElementById('supplierDownPaymentForm');
  if(dpForm){dpForm.addEventListener('submit',e=>{e.preventDefault();syncDpSupplierId();const f=Object.fromEntries(new FormData(e.target));if(!f.supplierId)return showAlert('Pilih supplier dari saran yang muncul.','error');const amount=Number(f.amount);if(amount<=0)return showAlert('Nominal DP tidak valid.','error');if(!validateCashPayment(f.date,amount))return;handle(async()=>{await insertRow('supplier_down_payments',{transaction_date:f.date,supplier_id:f.supplierId,amount,note:f.note||null},'DP supplier berhasil dicatat dan mengurangi sisa kas.');e.target.reset()})})}
  document.getElementById('purchaseForm').addEventListener('submit',e=>{e.preventDefault();syncPurchaseSupplierId();const form=e.target;const fd=new FormData(form);const f=Object.fromEntries(fd);if(!f.supplierId)return showAlert('Pilih supplier dari saran yang muncul.','error');handle(async()=>{const amount=Number(f.amount);let selectedDp=null,appliedDp=0;if(f.downPaymentId){selectedDp=db.supplierDownPayments.find(d=>d.id===f.downPaymentId&&!d.appliedPurchaseId&&d.supplierId===f.supplierId);if(!selectedDp)throw new Error('DP tidak valid atau sudah dipakai.');appliedDp=Math.min(Number(selectedDp.amount),amount);}const cashDue=Math.max(0,amount-appliedDp);if(f.paymentType==='cash'&&cashDue>0&&!validateCashPayment(f.date,cashDue))return;const file=fd.get('receipt');if(!file||!file.size)throw new Error('Nota wajib diunggah.');if(file.size>5*1024*1024)throw new Error('Ukuran nota maksimal 5 MB.');const {data:purchase,error:insertError}=await sb.from('purchases').insert({transaction_date:f.date,supplier_id:f.supplierId,amount,payment_type:f.paymentType,payment_method:'cash',note:f.note||null}).select('id').single();if(insertError)throw insertError;const ext=(file.name.split('.').pop()||'jpg').toLowerCase();const path=`${currentUser.id}/${f.date}/${purchase.id}.${ext}`;const {error:uploadError}=await sb.storage.from('purchase-receipts').upload(path,file,{upsert:false,contentType:file.type});if(uploadError){await sb.from('purchases').delete().eq('id',purchase.id);throw uploadError;}const {error:updateError}=await sb.from('purchases').update({receipt_path:path}).eq('id',purchase.id);if(updateError)throw updateError;if(selectedDp){const {error:dpError}=await sb.from('supplier_down_payments').update({applied_purchase_id:purchase.id,applied_amount:appliedDp}).eq('id',selectedDp.id);if(dpError)throw dpError;}await loadAll();showAlert(appliedDp?`Pembelian disimpan. DP ${fmt(appliedDp)} dipakai untuk mengurangi sisa pembayaran.`:'Pembelian supplier dan nota berhasil disimpan.');form.reset()})});
  document.getElementById('weeklyExpenseForm').addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));handle(async()=>{await insertRow('weekly_expenses',{transaction_date:f.date,category:f.category,amount:Number(f.amount),note:f.note,initial_status:f.status,payment_method:f.paymentMethod},'Pengeluaran mingguan berhasil dicatat.');e.target.reset()})});
  const dailyCashFlowFilter=document.getElementById('dailyCashFlowFilter');
  if(dailyCashFlowFilter){dailyCashFlowFilter.addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));dailyCashFlowDate=f.date;renderDailyCashFlow();});}
  const supplierReportFilter=document.getElementById('supplierReportFilter');
  if(supplierReportFilter){supplierReportFilter.addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));if(f.from>f.to)return showAlert('Tanggal awal tidak boleh lebih besar dari tanggal akhir.','error');supplierReportState.from=f.from;supplierReportState.to=f.to;pageState.supplierReportTable=1;renderSupplierReport();});}
}
function bindNav(){document.querySelectorAll('.nav-item').forEach(btn=>btn.addEventListener('click',()=>{document.querySelectorAll('.nav-item').forEach(x=>x.classList.remove('active'));btn.classList.add('active');const group=btn.closest('.nav-group');if(group)group.querySelector('.nav-parent')?.classList.add('active');document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));document.getElementById(btn.dataset.view).classList.add('active');document.getElementById('pageTitle').textContent=btn.dataset.title||btn.textContent;document.querySelector('.sidebar').classList.remove('open')}));document.getElementById('menuToggle').onclick=()=>document.querySelector('.sidebar').classList.toggle('open');document.getElementById('cycleDatePicker').onchange=e=>{selectedDate=e.target.value;dailyCashFlowDate=e.target.value;pageState={};renderAll()};document.getElementById('printReportBtn').onclick=()=>window.print();document.getElementById('refreshBtn').onclick=()=>handle(async()=>{await loadAll();showAlert('Data berhasil disinkronkan.')});document.getElementById('logoutBtn').onclick=()=>handle(async()=>{await sb.auth.signOut()});document.getElementById('seedDemoBtn').onclick=seedDemo;document.getElementById('closeReceiptModal').onclick=closeReceiptPreview;document.querySelectorAll('[data-close-receipt]').forEach(el=>el.onclick=closeReceiptPreview);document.addEventListener('keydown',e=>{if(e.key==='Escape')closeReceiptPreview()})}
async function seedDemo(){if(!isOwner())return showAlert('Hanya owner yang dapat mengisi data contoh.','error');if(!confirm('Tambahkan data contoh ke database online?'))return;const c=getCycle(selectedDate);await handle(async()=>{const {data:s,error}=await sb.from('suppliers').insert({name:'Supplier A',product_type:'Keranjang Rotan',phone:'081234567890',bank_name:'BCA',account_number:'1234567890',account_holder:'Supplier A',status:'Aktif'}).select().single();if(error)throw error;const rows=await Promise.all([sb.from('owner_cash').insert({transaction_date:c.start,amount:5000000,receiver:'Admin',note:'Dana operasional pagi'}),sb.from('daily_expenses').insert({transaction_date:c.start,category:'Bensin',amount:250000,note:'Bensin operasional'}),sb.from('purchases').insert({transaction_date:c.start,supplier_id:s.id,amount:2000000,payment_type:'tempo',payment_method:'cash',note:'Bayar Sabtu'}),sb.from('weekly_expenses').insert({transaction_date:c.start,category:'Gaji Karyawan',amount:3500000,note:'Total gaji minggu berjalan',initial_status:'unpaid',payment_method:'cash'})]);const bad=rows.find(r=>r.error);if(bad)throw bad.error;await loadAll();showAlert('Data contoh berhasil ditambahkan.')})}
async function loadProfile(){
  const {data,error}=await sb.from('profiles').select('id,full_name,role').eq('id',currentUser.id).single();
  if(error)throw new Error('Profil pengguna belum diatur. Jalankan pengaturan Aan dan Febri pada SQL Supabase.');
  currentProfile=data;
}
function applyRoleUi(){
  const box=document.getElementById('userIdentity');
  if(box&&currentProfile){box.innerHTML=`<strong>${currentProfile.full_name}</strong><span>${currentProfile.role==='owner'?'Owner':'Sekretaris'}</span>`;}
  const demo=document.getElementById('seedDemoBtn'); if(demo)demo.classList.toggle('hidden',!isOwner());
  document.body.dataset.role=currentProfile?.role||'';
}
async function showApp(session){
  currentUser=session?.user||null; currentProfile=null;
  document.getElementById('authScreen').classList.toggle('hidden',!!currentUser);
  document.getElementById('appShell').classList.toggle('hidden',!currentUser);
  if(currentUser){await loadProfile();applyRoleUi();await loadAll();}
}

async function init(){bindForms();bindNav();document.getElementById('loginForm').addEventListener('submit',e=>{e.preventDefault();const f=Object.fromEntries(new FormData(e.target));if(!sb)return showAuthMessage('Konfigurasi Supabase belum dipasang.');handle(async()=>{const {error}=await sb.auth.signInWithPassword({email:f.email,password:f.password});if(error)throw error})});if(!sb){showAuthMessage('SUPABASE_URL dan SUPABASE_ANON_KEY belum tersedia. Jalankan build Netlify atau isi config.js.');return}const {data:{session}}=await sb.auth.getSession();await handle(()=>showApp(session));sb.auth.onAuthStateChange((_event,session)=>handle(()=>showApp(session)))}
init();
